module top_module(state, workload, enable, clk);input [2:0] state; 
input [5:0] workload; 
output enable; 
input clk; 
reg enable_reg;
assign enable = enable_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or posedge dbg_halt)
begin
	if(state == 0 && workload == 0 ) 
	begin
		enable_reg = 1;		
	end
	else 
	begin
		enable_reg = 0;
	end
end

endmodule
